function redact(text = '') {
  // Keep customer email and phone visible in support logs; they are operational
  // contact details. Still redact high-risk identifiers that should not sit in
  // general workflow logs.
  return String(text).trim()
    .replace(/\b[STFGM]\d{7}[A-Z]\b/gi, '[redacted-nric-fin]')
    .replace(/\b\d{9,}\b/g, '[redacted-id]');
}

function normaliseForDedupe(text = '') {
  return redact(text).toLowerCase().replace(/\s+/g, ' ').trim();
}

function hashText(text = '') {
  let hash = 2166136261;
  for (const char of text) {
    hash ^= char.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function shortSession(value = '') {
  return String(value || 'session').replace(/[^a-z0-9]/gi, '').slice(0, 8) || 'session';
}

function sgtDateKey(date = new Date()) {
  const shifted = new Date(date.getTime() + 8 * 60 * 60 * 1000);
  const pad = (value) => String(value).padStart(2, '0');
  return '' + shifted.getUTCFullYear() + pad(shifted.getUTCMonth() + 1) + pad(shifted.getUTCDate());
}

function conversationRef(item) {
  const sessionId = item.session_id || item.sessionId || item.chatId || 'unknown_session';
  const suffix = hashText(String(sessionId)).toUpperCase().slice(0, 6);
  return item.conversation_ref || 'SKR-CONV-' + sgtDateKey() + '-' + suffix;
}

function dedupeKey(item, bucketOffset = 0) {
  const bucketSizeMs = 2 * 60 * 1000;
  const bucket = Math.floor(Date.now() / bucketSizeMs) + bucketOffset;
  const sessionId = item.session_id || item.sessionId || item.chatId || 'unknown_session';
  const messageHash = hashText(normaliseForDedupe(item.message)).toUpperCase();
  return 'SKR-DEDUP-' + shortSession(sessionId) + '-' + messageHash + '-' + bucket;
}

return items.map((item) => ({
  json: {
    ...item.json,
    user_message_redacted: redact(item.json.message),
    conversation_ref: conversationRef(item.json),
    dedupe_key: dedupeKey(item.json),
    dedupe_key_previous: dedupeKey(item.json, -1)
  }
}));

function parseAgentOutput(value) {
  if (typeof value === 'object' && value !== null) return value;
  const text = String(value || '').trim();
  try {
    return JSON.parse(text);
  } catch (error) {
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start >= 0 && end > start) return JSON.parse(text.slice(start, end + 1));
    throw error;
  }
}

function sgtParts(date = new Date()) {
  const shifted = new Date(date.getTime() + 8 * 60 * 60 * 1000);
  const pad = (value, length = 2) => String(value).padStart(length, '0');
  return {
    year: shifted.getUTCFullYear(),
    month: pad(shifted.getUTCMonth() + 1),
    day: pad(shifted.getUTCDate()),
    hour: pad(shifted.getUTCHours()),
    minute: pad(shifted.getUTCMinutes()),
    second: pad(shifted.getUTCSeconds()),
    ms: pad(shifted.getUTCMilliseconds(), 3),
  };
}

function sgtTimestamp(date = new Date()) {
  const parts = sgtParts(date);
  return parts.year + '-' + parts.month + '-' + parts.day + ' ' + parts.hour + ':' + parts.minute + ':' + parts.second + ' SGT';
}

function timestampForId(date = new Date()) {
  const parts = sgtParts(date);
  return '' + parts.year + parts.month + parts.day + '-' + parts.hour + parts.minute + parts.second;
}

function hashText(text = '') {
  let hash = 2166136261;
  for (const char of String(text)) {
    hash ^= char.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36).toUpperCase();
}

function meaningful(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^(n\/a|na|none|null|unknown|not_available)$/i.test(text)) return '';
  return text;
}

function firstMeaningful(...values) {
  for (const value of values) {
    const text = meaningful(value);
    if (text) return text;
  }
  return '';
}

function driveFileUrl(value = '') {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^https?:\/\//i.test(text)) return text;
  return 'https://drive.google.com/file/d/' + text + '/view';
}

function sourceUrls(values = []) {
  return values.map(driveFileUrl).filter(Boolean);
}

return items.map((item) => {
  const original = $('Restore Processing Context').first().json || {};
  const raw = item.json.output || item.json.text || item.json.response || item.json;
  let parsed;
  try {
    parsed = parseAgentOutput(raw);
  } catch (error) {
    parsed = {
      reply: 'I do not have that detail yet. I can help escalate this to the SpaceKonceptRental team.',
      intent: 'unknown',
      confidence: 0,
      needs_escalation: true,
      needs_human_followup: true,
      lead_captured: false,
      ticket_required: false,
      booking_requested: false,
      missing_fields: [],
      lead: {},
      ticket: {},
      booking: {},
      retrieval_summary: { source_titles: [], source_file_ids: [] }
    };
  }

  const now = new Date();
  const idTime = timestampForId(now);
  const referenceSuffix = hashText([original.session_id, original.message_id, original.message].join('|')).slice(0, 6);
  const conversationRef = firstMeaningful(original.conversation_ref) || 'SKR-CONV-' + String(idTime).split('-')[0] + '-' + hashText(original.session_id || original.message_id).slice(0, 6);
  const ticketRequired = Boolean(parsed.ticket_required);
  const lead = parsed.lead || {};
  const ticket = parsed.ticket || {};
  const customerName = firstMeaningful(parsed.lead?.name, parsed.ticket?.name, original.customer_name);
  const customerEmail = firstMeaningful(parsed.lead?.email, parsed.ticket?.email, original.customer_email);
  const customerPhone = firstMeaningful(parsed.lead?.phone, parsed.ticket?.phone, original.customer_phone);
  const ticketName = firstMeaningful(ticket.name, lead.name, customerName);
  const ticketEmail = firstMeaningful(ticket.email, lead.email, customerEmail);
  const ticketPhone = firstMeaningful(ticket.phone, lead.phone, customerPhone);
  const ticketIssue = firstMeaningful(ticket.summary, ticket.details);
  const ticketReady = ticketRequired && Boolean(ticketName) && Boolean(ticketEmail || ticketPhone) && Boolean(ticketIssue);
  const leadCaptured = !ticketRequired && Boolean(parsed.lead_captured);
  const bookingRequested = !ticketRequired && Boolean(parsed.booking_requested);
  const leadRequired = leadCaptured || bookingRequested;
  const ticketId = ticketReady ? 'SKR-TKT-' + idTime + '-' + referenceSuffix : '';
  const leadId = leadRequired ? 'SKR-LEAD-' + idTime + '-' + referenceSuffix : '';
  const escalationReferenceId = parsed.needs_escalation ? (ticketId || leadId || original.message_id) : '';

  return {
    json: {
      ...original,
      ...item.json,
      conversation_ref: conversationRef,
      agent_raw_output: raw,
      reply: parsed.reply || 'I do not have that detail yet. I can help escalate this to the SpaceKonceptRental team.',
      intent: parsed.intent || 'unknown',
      confidence: Number(parsed.confidence || 0),
      needs_escalation: Boolean(parsed.needs_escalation),
      needs_human_followup: Boolean(parsed.needs_human_followup),
      lead_captured: leadCaptured,
      ticket_required: ticketRequired,
      ticket_ready: ticketReady,
      booking_requested: bookingRequested,
      missing_fields: parsed.missing_fields || [],
      customer_name: customerName,
      customer_email: customerEmail,
      customer_phone: customerPhone,
      lead: {
        ...lead,
        name: firstMeaningful(lead.name, ticket.name, customerName),
        email: firstMeaningful(lead.email, ticket.email, customerEmail),
        phone: firstMeaningful(lead.phone, ticket.phone, customerPhone),
      },
      ticket: {
        ...ticket,
        name: ticketName,
        email: ticketEmail,
        phone: ticketPhone,
      },
      booking: parsed.booking || {},
      source_titles: (parsed.retrieval_summary?.source_titles || []).join(', '),
      source_file_ids: sourceUrls(parsed.retrieval_summary?.source_file_ids || []).join(', '),
      ticket_id: ticketId,
      lead_id: leadId,
      escalation_reference_id: escalationReferenceId,
      completed_at: sgtTimestamp(now),
      unanswered_id: 'SKR-UNANSWERED-' + idTime + '-' + referenceSuffix
    }
  };
});

const debounceWindowMs = 20 * 1000;
const now = Date.now();
const current = $('Redact PII for Logs').first().json || {};

function parseSgtTimestamp(value) {
  const match = String(value || '').trim().match(/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2}):(\d{2}) SGT$/);
  if (!match) return NaN;
  const [, year, month, day, hour, minute, second] = match.map(Number);
  return Date.UTC(year, month - 1, day, hour - 8, minute, second);
}

function rowTime(row) {
  const value = row.created_at || row.timestamp || current.timestamp || '';
  const sgtParsed = parseSgtTimestamp(value);
  if (Number.isFinite(sgtParsed)) return sgtParsed;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function meaningful(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^(n\/a|na|none|null|unknown|not_available|pending|pending_ai_response|queued_for_ai_response)$/i.test(text)) return '';
  return text;
}

function messageText(row) {
  return meaningful(row.message) || meaningful(row.user_message_redacted);
}

function uniqueByMessageId(rows) {
  const byId = new Map();
  for (const row of rows) {
    const key = String(row.message_id || '').trim();
    if (!key) continue;
    byId.set(key, row);
  }
  return [...byId.values()];
}

function executionOrder(row) {
  const parsed = Number(String(row.execution_id || '').replace(/[^0-9]/g, ''));
  return Number.isFinite(parsed) ? parsed : 0;
}

const currentTime = rowTime(current) || now;
const sheetRows = items.map((item) => item.json || {});
const currentRow = { ...current, status: 'queued' };
const rows = uniqueByMessageId([...sheetRows, currentRow])
  .filter((row) => String(row.session_id || '') === String(current.session_id || ''))
  .map((row) => ({ ...row, _row_time: rowTime(row) || currentTime }))
  .filter((row) => Math.abs(row._row_time - currentTime) <= debounceWindowMs)
  .filter((row) => ['queued', 'merged', 'processing'].includes(String(row.status || '').toLowerCase()))
  .sort((a, b) =>
    (a._row_time - b._row_time) ||
    (executionOrder(a) - executionOrder(b)) ||
    String(a.message_id || '').localeCompare(String(b.message_id || ''))
  );

const latest = rows[rows.length - 1] || currentRow;
if (String(latest.message_id || '') !== String(current.message_id || '')) {
  return [{
    json: {
      ...current,
      debounce_superseded: 'true',
      debounce_latest_message_id: latest.message_id || '',
      debounce_batch_count: rows.length,
    },
  }];
}

const batchRows = rows.length ? rows : [currentRow];
const mergedTexts = batchRows
  .map((row, index) => {
    const text = messageText(row);
    return text ? String(index + 1) + '. ' + text : '';
  })
  .filter(Boolean);

const mergedMessage = mergedTexts.length > 1
  ? 'The customer sent these rapid messages in order. Treat them as one customer turn:\n\n' + mergedTexts.join('\n')
  : (meaningful(current.message) || meaningful(current.user_message_redacted));

return [{
  json: {
    ...current,
    message: mergedMessage,
    user_message_redacted: mergedTexts.length > 1 ? mergedTexts.join('\n') : current.user_message_redacted,
    debounce_superseded: 'false',
    debounce_batch_count: batchRows.length,
    merged_message_ids: batchRows.map((row) => row.message_id).filter(Boolean).join(', '),
  },
}];

function escapeHtml(value = '') {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function meaningful(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^(n\/a|na|none|null|unknown|not_available|not provided|pending)$/i.test(text)) return '';
  return text;
}

function firstMeaningful(...values) {
  for (const value of values) {
    const text = meaningful(value);
    if (text) return text;
  }
  return '';
}

function boolText(value) {
  return String(value).toLowerCase() === 'true' ? 'Yes' : 'No';
}

function rowTime(row) {
  return meaningful(row.created_at) || meaningful(row.completed_at) || '';
}

const original = $('Parse Strict JSON Response').first().json || {};
const rows = items
  .map((item) => item.json || {})
  .filter((row) => String(row.session_id || '') === String(original.session_id || ''))
  .sort((a, b) => String(rowTime(a)).localeCompare(String(rowTime(b))));

const transcriptRows = rows.length ? rows : [original];
const transcriptHtml = transcriptRows.map((row, index) => {
  const when = rowTime(row) || 'time_not_available';
  const customerMessage = meaningful(row.user_message_redacted) || meaningful(row.message) || '';
  const botReply = meaningful(row.bot_reply) || meaningful(row.reply) || '';
  const intent = meaningful(row.intent);

  return [
    '<div style="border-left:3px solid #d9e2ec;padding:8px 0 8px 12px;margin:10px 0;">',
    '<p style="margin:0 0 4px 0;color:#52606d;"><strong>#' + (index + 1) + '</strong> · ' + escapeHtml(when) + (intent ? ' · ' + escapeHtml(intent) : '') + '</p>',
    customerMessage ? '<p style="margin:0 0 6px 0;"><strong>Customer:</strong> ' + escapeHtml(customerMessage) + '</p>' : '',
    botReply ? '<p style="margin:0;"><strong>Bot:</strong> ' + escapeHtml(botReply) + '</p>' : '',
    '</div>',
  ].join('');
}).join('');

const transcriptText = transcriptRows.map((row, index) => {
  const when = rowTime(row) || 'time_not_available';
  const customerMessage = meaningful(row.user_message_redacted) || meaningful(row.message) || '';
  const botReply = meaningful(row.bot_reply) || meaningful(row.reply) || '';
  const intent = meaningful(row.intent);
  return [
    '#' + (index + 1) + ' - ' + when + (intent ? ' - ' + intent : ''),
    customerMessage ? 'Customer: ' + customerMessage : '',
    botReply ? 'Bot: ' + botReply : '',
  ].filter(Boolean).join('\n');
}).join('\n\n');

const conversationRef = firstMeaningful(original.conversation_ref, original.ticket_id, original.lead_id, original.message_id);
const caseReference = firstMeaningful(original.ticket_id, original.lead_id, original.message_id);

const customerName = firstMeaningful(original.customer_name, original.lead?.name, original.ticket?.name);
const customerEmail = firstMeaningful(original.customer_email, original.lead?.email, original.ticket?.email);
const customerPhone = firstMeaningful(original.customer_phone, original.lead?.phone, original.ticket?.phone);

return [{
  json: {
    ...original,
    customer_name: customerName,
    customer_email: customerEmail,
    customer_phone: customerPhone,
    conversation_ref: conversationRef,
    conversation_transcript_text: transcriptText || 'No previous conversation rows found for this session.',
    notification_contact_line: [customerName, customerEmail, customerPhone].filter(Boolean).join(' | ') || 'Contact not provided',
    notification_subject_label: firstMeaningful(original.ticket?.summary, original.lead?.items_needed, original.intent, 'Support update'),
    notification_summary_html: [
      '<table cellpadding="6" cellspacing="0" style="border-collapse:collapse;width:100%;max-width:760px;">',
      '<tr><td style="width:150px;color:#52606d;"><strong>Conversation</strong></td><td>' + escapeHtml(conversationRef) + '</td></tr>',
      '<tr><td style="color:#52606d;"><strong>Case</strong></td><td>' + escapeHtml(caseReference) + '</td></tr>',
      '<tr><td style="color:#52606d;"><strong>Session</strong></td><td>' + escapeHtml(original.session_id || '') + '</td></tr>',
      '<tr><td style="color:#52606d;"><strong>Contact</strong></td><td>' + escapeHtml([customerName, customerEmail, customerPhone].filter(Boolean).join(' | ') || 'not_available') + '</td></tr>',
      '<tr><td style="color:#52606d;"><strong>Intent</strong></td><td>' + escapeHtml(original.intent || '') + '</td></tr>',
      '<tr><td style="color:#52606d;"><strong>Escalation</strong></td><td>' + escapeHtml(boolText(original.needs_escalation)) + '</td></tr>',
      '<tr><td style="color:#52606d;"><strong>Completed</strong></td><td>' + escapeHtml(original.completed_at || '') + '</td></tr>',
      '</table>',
    ].join(''),
    conversation_message_count: transcriptRows.length,
    conversation_transcript_html: transcriptHtml || '<p>No previous conversation rows found for this session.</p>',
  },
}];
